3188 void InstCombinerImpl::addDeadEdge(BasicBlock *From, BasicBlock *To,
3189                                    SmallVectorImpl<BasicBlock *> &Worklist) {
3190   if (!DeadEdges.insert({From, To}).second)
3191     return;
3192 
3193   // Replace phi node operands in successor with poison.
3194   for (PHINode &PN : To->phis())
3195     for (Use &U : PN.incoming_values())
